1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Step = QuoteStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	type QuoteResult = { premium: number };
9	type Output = { results: QuoteResult[] };
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	};
16	
17	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
18	
19	const quote = (step: QuoteStep): QuoteResult => {
20	  const base = step.items.reduce((sum, item) => sum + basePremium(item), 0);
21	  const firstInsurance = base * FIRST_INSURANCE_RATE;
22	  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
23	};
24	
25	export const run = (input: unknown): Output => {
26	  const scenario = input as Scenario;
27	  return { results: scenario.steps.map(quote) };
28	};
